import React, { useEffect, useState } from "react";
import Navbar from "../../components/Navbar";
import api from "../../api/axiosInstance";
import styles from "./AdminPages.module.css";

const ManagePackagesPage = () => {

  const [packages, setPackages] = useState([]);
  const [destinations, setDestinations] = useState([]);

  const [formData, setFormData] = useState({
    name: "",
    destination: "",
    duration: "",
    price: "",
    availableSlots: "",
    description: "",
    transportation: "",
    sightseeing: "",
    meals: "",
    itinerary: ""
  });

  const [hotels, setHotels] = useState([
    { name: "", pricePerDay: "", description: "", image: "" }
  ]);

  // ================= LOAD =================
  useEffect(() => {
    loadPackages();
    loadDestinations();
  }, []);

  const loadPackages = async () => {
    const res = await api.get("/packages");
    setPackages(res.data.data);
  };

  const loadDestinations = async () => {
    const res = await api.get("/destinations");
    setDestinations(res.data.data);
  };

  // ================= INPUT =================
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleHotelChange = (index, e) => {
    const updated = [...hotels];
    updated[index][e.target.name] = e.target.value;
    setHotels(updated);
  };

  const addHotel = () => {
    setHotels([
      ...hotels,
      { name: "", pricePerDay: "", description: "", image: "" }
    ]);
  };

  // ================= SUBMIT =================
  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      ...formData,
      transportation: formData.transportation.split(","),
      sightseeing: formData.sightseeing.split(","),
      meals: formData.meals.split(","),
      itinerary: formData.itinerary.split(","),
      hotels: hotels
    };

    await api.post("/packages", payload);

    alert("✅ Package Added!");

    loadPackages();
  };

  return (
    <>
      <Navbar />

      <div className={styles.container}>

        <h1>✈️ Manage Packages</h1>

        {/* ================= FORM ================= */}
        <form onSubmit={handleSubmit} className={styles.form}>

          <input name="name" placeholder="Package Name" onChange={handleChange} />

          <select name="destination" onChange={handleChange}>
            <option value="">Select Destination</option>
            {destinations.map(d => (
              <option key={d._id} value={d._id}>{d.name}</option>
            ))}
          </select>

          <input name="duration" placeholder="Duration (4N/5D)" onChange={handleChange} />
          <input name="price" placeholder="Price" onChange={handleChange} />
          <input name="availableSlots" placeholder="Slots" onChange={handleChange} />

          <textarea name="description" placeholder="Description" onChange={handleChange} />
          <textarea name="transportation" placeholder="Transportation" onChange={handleChange} />
          <textarea name="sightseeing" placeholder="Sightseeing" onChange={handleChange} />
          <textarea name="meals" placeholder="Meals" onChange={handleChange} />
          <textarea name="itinerary" placeholder="Itinerary" onChange={handleChange} />

          {/* HOTELS */}
          <h3>🏨 Hotels</h3>

          {hotels.map((hotel, index) => (
            <div key={index} className={styles.hotelCard}>
              <input name="name" placeholder="Hotel Name" onChange={(e) => handleHotelChange(index, e)} />
              <input name="pricePerDay" placeholder="Price per day" onChange={(e) => handleHotelChange(index, e)} />
              <input name="image" placeholder="Image URL" onChange={(e) => handleHotelChange(index, e)} />
              <textarea name="description" placeholder="Description" onChange={(e) => handleHotelChange(index, e)} />
            </div>
          ))}

          <button type="button" onClick={addHotel}>➕ Add Hotel</button>

          <button type="submit">Add Package</button>

        </form>

        {/* ================= TABLE ================= */}
        <div className={styles.tableSection}>

          <h2>📦 Existing Packages</h2>

          <table className={styles.table}>
            <thead>
              <tr>
                <th>Name</th>
                <th>Destination</th>
                <th>Duration</th>
                <th>Price</th>
                <th>Hotels</th>
              </tr>
            </thead>

            <tbody>
              {packages.map((pkg) => (
                <tr key={pkg._id}>
                  <td>{pkg.name}</td>
                  <td>{pkg.destination?.name || "—"}</td>
                  <td>{pkg.duration}</td>
                  <td>₹{pkg.price}</td>
                  <td>{pkg.hotels?.length || 0}</td>
                </tr>
              ))}
            </tbody>
          </table>

        </div>

      </div>
    </>
  );
};

export default ManagePackagesPage;
